 1	import React, { FC, useState } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { isEmpty } from '@kubevirt-utils/utils/utils';
 5	import { ExpandableSection } from '@patternfly/react-core';
 6	
 7	import { useDrawerContext } from './hooks/useDrawerContext';
 8	import { FieldGroup } from './FieldGroup';
 9	import { changeTemplateParameterValue, getTemplateParametersSplit } from './utils';
10	
11	const FieldsSections: FC = () => {
12	  const { t } = useKubevirtTranslation();
13	
14	  const { setTemplate, template } = useDrawerContext();
15	  const [requiredParameters, optionalParameters] = getTemplateParametersSplit(template?.parameters);
16	
17	  const [requiredSectionOpen, setRequiredSectionOpen] = useState(true);
18	
19	  const onFieldValueChange = (name: string, value: string) => {
20	    setTemplate((draftTemplate) => changeTemplateParameterValue(draftTemplate, name, value));
21	  };
22	  return (
23	    <>
24	      {!isEmpty(requiredParameters) && (
25	        <ExpandableSection
26	          isExpanded={requiredSectionOpen}
27	          isIndented
28	          onToggle={(_event, val) => setRequiredSectionOpen(val)}
29	          toggleText={t('Required parameters')}
30	        >
31	          {requiredParameters.map((param) => (
32	            <FieldGroup field={param} key={param.name} onChange={onFieldValueChange} />
33	          ))}
34	        </ExpandableSection>
35	      )}
36	      {!isEmpty(optionalParameters) && (
37	        <ExpandableSection isIndented toggleText={t('Optional parameters')}>
38	          {optionalParameters.map((param) => (
39	            <FieldGroup field={param} key={param.name} onChange={onFieldValueChange} />
40	          ))}
41	        </ExpandableSection>
42	      )}
43	    </>
44	  );
45	};
46	
47	export default FieldsSections;

